      <!-- abilities list -->
      <div style="margin-top:13px"><label style="font-size:10px;letter-spacing:1.5px;color:var(--dim);text-transform:uppercase" data-en="Abilities & Skills" data-th="ความสามารถ & สกิล">Abilities & Skills</label>
        <div class="list" id="abList"></div>
