      <div class="addrow" id="itAdd" data-en="+ ADD ITEM / CONSTRUCT" data-th="+ เพิ่มไอเทม / คอนสตรัค">+ ADD ITEM / CONSTRUCT</div>
      <div class="adder" id="itForm">
        <div class="row"><input class="inp" id="itN" placeholder="Name"/>
