</div>

<script>
(function(){
  function g(id){return document.getElementById(id);}
  var S={th:'dark',ln:'en',stand:'',power:[],rank:'',ab:[],it:[],cf:[]};
  var STAND=[['Noble','ชนชั้นสูง'],['Commoner','สามัญชน'],['Merchant','พ่อค้า'],['Outlaw','คนนอกกฎหมาย'],['Slave','ทาส'],['Wanderer','คนพเนจร']];
  var POWERS=[['False Magic','เวทมนุษย์'],['True Magic','เวทแท้'],['Aura','ออร่า'],['Formless Aura','ไร้รูป'],['Blood Aura','ออร่าเลือด'],['Sage Mana','มานาเซียน'],['Divine Mana','มานาบริสุทธิ์'],['Construct','คอนสตรัค'],['Divine Construct','บรรพกาล']];
  var RANKS=[['Rookie','ROOKIE'],['Basic','BASIC'],['Intermediate','INTERMEDIATE'],['Ember','EMBER'],['Custom','CUSTOM']];

  function buildChips(){
    var w=g('standChips');w.innerHTML='';
    STAND.forEach(function(p){var c=document.createElement('span');c.className='chip';c.dataset.v=p[0];
      c.textContent=(S.ln==='th'?p[1]:p[0]);c.onclick=function(){S.stand=(S.stand===p[0]?'':p[0]);paintChips();};w.appendChild(c);});
    var add=document.createElement('span');add.className='chip add';add.textContent=(S.ln==='th'?'+ กำหนดเอง':'+ custom');
    add.onclick=function(){var v=prompt(S.ln==='th'?'สถานะ:':'Standing:');if(v){S.stand=v;buildChips();}};w.appendChild(add);
    paintChips();
  }
  function paintChips(){[].forEach.call(g('standChips').querySelectorAll('.chip'),function(c){if(!c.classList.contains('add'))c.classList.toggle('on',c.dataset.v===S.stand||c.textContent===S.stand);});}

  function buildPowers(){
    var w=g('powerGrid');w.innerHTML='';
    POWERS.forEach(function(p){var c=document.createElement('div');c.className='pcard';
      c.innerHTML='<span>'+p[0]+'</span><small>'+p[1]+'</small>';
      c.onclick=function(){var i=S.power.indexOf(p[0]);if(i>=0)S.power.splice(i,1);else S.power.push(p[0]);c.classList.toggle('on');};
      if(S.power.indexOf(p[0])>=0)c.classList.add('on');w.appendChild(c);});
  }
  function buildRanks(){
    var w=g('rankRow');w.innerHTML='';
    RANKS.forEach(function(r){var c=document.createElement('span');c.className='rk';c.textContent=r[1];
      c.onclick=function(){S.rank=r[0];[].forEach.call(w.children,function(x){x.classList.remove('on');});c.classList.add('on');
        g('fRankCustom').style.display=(r[0]==='Custom'?'block':'none');};
      if(S.rank===r[0])c.classList.add('on');w.appendChild(c);});
  }
  function renderList(arr,el,fmt){var w=g(el);w.innerHTML='';arr.forEach(function(o,idx){var d=document.createElement('div');d.className='li';
    d.innerHTML='<span class="ic">◆</span><div class="tx">'+fmt(o)+'</div><span class="rm">✕</span>';
    d.querySelector('.rm').onclick=function(){arr.splice(idx,1);renderList(arr,el,fmt);};w.appendChild(d);});}
  function rAb(){renderList(S.ab,'abList',function(o){return '<b>'+esc(o.n)+'</b>'+(o.t?' <span>· '+esc(o.t)+'</span>':'')+(o.d?'<br><span>'+esc(o.d)+'</span>':'');});}
  function rIt(){renderList(S.it,'itList',function(o){return '<b>'+esc(o.n)+'</b> <span>· '+esc(o.t)+'</span>'+(o.d?'<br><span>'+esc(o.d)+'</span>':'');});}
  function rCf(){renderList(S.cf,'cfList',function(o){return '<b>'+esc(o.n)+'</b><br><span>'+esc(o.d)+'</span>';});}
  function esc(s){return String(s||'').replace(/[<>&]/g,function(c){return{'<':'&lt;','>':'&gt;','&':'&amp;'}[c];});}

  function applyLabels(){
    [].forEach.call(document.querySelectorAll('[data-en]'),function(e){var t=(S.ln==='th'?e.getAttribute('data-th'):e.getAttribute('data-en'));if(t!=null)e.textContent=t;});
    [].forEach.call(document.querySelectorAll('#trapp option[data-en]'),function(o){o.textContent=(S.ln==='th'?o.getAttribute('data-th'):o.getAttribute('data-en'));});
    buildChips();
  }

  window.TR={
    init:function(){
      g('trapp').classList.add('loading');
      buildChips();buildPowers();buildRanks();rAb();rIt();rCf();
      g('trSkip').onclick=function(){TR.skip();};
      g('abAdd').onclick=function(){g('abForm').classList.toggle('open');};
      g('itAdd').onclick=function(){g('itForm').classList.toggle('open');};
      g('cfAdd').onclick=function(){g('cfForm').classList.toggle('open');};
      TR.runLoader();
    },
    runLoader:function(){
      var p=0,bar=g('ldBar'),pct=g('ldPct');S._done=false;
      var msgs=['UNSEALING THE WORLD GATE','CALIBRATING AURA FIELD','INSCRIBING YOUR NAME INTO FATE','LINK ESTABLISHED'];
      var iv=setInterval(function(){p+=Math.random()*9+3;if(p>=100){p=100;clearInterval(iv);setTimeout(TR.skip,420);}
        bar.style.width=p+'%';pct.textContent=Math.floor(p)+'%';
        g('ldLbl').textContent=msgs[Math.min(msgs.length-1,Math.floor(p/26))];},170);
      S._iv=iv;
    },
    skip:function(){if(S._done)return;S._done=true;clearInterval(S._iv);g('trLoader').classList.add('gone');setTimeout(function(){g('trapp').classList.remove('loading');},700);},
    th:function(){S.th=(S.th==='dark'?'light':'dark');g('trapp').classList.toggle('lt',S.th==='light');},
    ln:function(l){S.ln=l;g('lnEn').classList.toggle('on',l==='en');g('lnTh').classList.toggle('on',l==='th');
      g('ldSub').textContent=(l==='th'?'ก้าวเข้าสู่โลก':'E N T E R   T H E   W O R L D');applyLabels();buildPowers();buildRanks();},
    closeAdd:function(f,a){g(f).classList.remove('open');},
    addAb:function(){var n=g('abN').value.trim();if(!n){g('abN').focus();return;}S.ab.push({n:n,t:g('abT').value.trim(),d:g('abD').value.trim()});g('abN').value=g('abT').value=g('abD').value='';g('abForm').classList.remove('open');rAb();},
    addIt:function(){var n=g('itN').value.trim();if(!n){g('itN').focus();return;}S.it.push({n:n,t:g('itT').value,d:g('itD').value.trim()});g('itN').value=g('itD').value='';g('itForm').classList.remove('open');rIt();},
    addCf:function(){var n=g('cfN').value.trim();if(!n){g('cfN').focus();return;}S.cf.push({n:n,d:g('cfD').value.trim()});g('cfN').value=g('cfD').value='';g('cfForm').classList.remove('open');rCf();},
    rnd:function(){
      var names=['Aerix','Vael','Sornn','Kael','Mireu','Dravoss','Liraen','Tharos'];
      var hair=['Silver','Ashen black','Crimson','White-gold','Deep blue'];var eyes=['Crimson','Pale gold','Storm-grey','Violet','Amber'];
      if(!g('fName').value)g('fName').value=names[Math.floor(Math.random()*names.length)];
      if(!g('fHair').value)g('fHair').value=hair[Math.floor(Math.random()*hair.length)];
      if(!g('fEyes').value)g('fEyes').value=eyes[Math.floor(Math.random()*eyes.length)];
      if(S.power.length===0){S.power.push(POWERS[Math.floor(Math.random()*POWERS.length)][0]);buildPowers();}
      if(!S.rank){S.rank=RANKS[Math.floor(Math.random()*4)][0];buildRanks();}
    },
    send:function(){
      var name=g('fName').value.trim();
      if(!name){g('fName').focus();g('fName').style.borderLeftColor='#ff6b6b';return;}
      var data={
        name:name,title:g('fTitle').value.trim(),gender:g('fGender').value.trim(),pronouns:g('fPron').value.trim(),age:g('fAge').value.trim(),race:g('fRace').value.trim(),
        home_continent:g('fCont').value,birthplace:g('fBirth').value.trim(),social_standing:S.stand,
        appearance:{hair:g('fHair').value.trim(),eyes:g('fEyes').value.trim(),height:g('fHeight').value.trim(),build:g('fBuild').value.trim(),marks:g('fMarks').value.trim(),full:g('fAppear').value.trim()},
        power_types:S.power,origin_skill:g('fOrigin').value.trim(),origin_skill_desc:g('fOriginD').value.trim(),mastery:g('fMastery').value,abilities:S.ab,
        arsenal:S.it,
        profession:g('fProf').value.trim(),adventurer_rank:(S.rank==='Custom'?(g('fRankCustom').value.trim()||'Custom'):S.rank),affiliation:g('fAffil').value.trim(),
        personality:g('fPers').value.trim(),backstory:g('fBack').value.trim(),goal:g('fGoal').value.trim(),opening_scene:g('fScene').value.trim(),
        custom_fields:S.cf,ui_theme:S.th,ui_lang:S.ln
      };
      g('trSnd').classList.add('on');
      var oT='<'+'TR_CONFIRM'+'>';var cT='<'+'/TR_CONFIRM'+'>';
      var txt=oT+'\n'+JSON.stringify(data,null,2)+'\n'+cT;
      setTimeout(function(){
        try{var w=window.parent||window;var ta=w.document.getElementById('send_textarea')||w.document.querySelector('textarea.chat-input,#textareaAutosize,textarea');
          if(ta){var dd=Object.getOwnPropertyDescriptor(w.HTMLTextAreaElement.prototype,'value');if(dd&&dd.set)dd.set.call(ta,txt);else ta.value=txt;ta.dispatchEvent(new Event('input',{bubbles:true}));
          setTimeout(function(){try{var sb=w.document.getElementById('send_but');if(sb)sb.click();else ta.dispatchEvent(new KeyboardEvent('keydown',{key:'Enter',keyCode:13,bubbles:true}));}catch(e){}},150);return;}}catch(e){}
        try{navigator.clipboard.writeText(txt);}catch(e){}
      },500);
    }
  };
  TR.init();
})();
</script>
